//! `baton-do rmdir` logic: remove a collection at the path
//! specified by the input target.
//!
//! Wraps the existing `RodsConnection::rm_collection` (which
//! itself wraps `shim_rm_coll` over `rcRmColl`). Both flags are
//! caller-controlled to match upstream baton-do
//! (`baton/src/operations.c:822-870`):
//!
//! - `recurse` removes a populated collection in one call
//!   (`RECURSIVE_OPR__KW`). Without it, iRODS returns
//!   `CAT_COLLECTION_NOT_EMPTY` against a non-empty target.
//! - `force` removes permanently rather than moving to the trash
//!   collection (`FORCE_FLAG_KW`).
//!
//! Distinct from `baton-do remove` — `remove` is data-objects-
//! only and always sets `FORCE_FLAG_KW` server-side. Type
//! mismatch on either errors before any iRODS call rather than
//! auto-routing.
//!
//! Data-object targets are an error — rmdir is collection-only.
//!
//! With `recurse = true`, the server-side walk has no
//! client-side ceiling — a recursive removal on a high-level
//! collection wipes every descendant in one call. Matches
//! upstream baton; iRODS itself has no max-depth bound either.
//! Use with care on large trees.

use crate::connection::RodsConnection;
use crate::error::BatonError;
use crate::types::Target;

/// Caller-controlled flags for [`rmdir_one`].
#[derive(Debug, Default, Clone, Copy)]
pub struct RmdirOptions {
    /// Recurse into a populated collection (`RECURSIVE_OPR__KW`).
    /// Without this iRODS returns `CAT_COLLECTION_NOT_EMPTY` on a
    /// non-empty target.
    pub recurse: bool,

    /// Permanent delete rather than trashing
    /// (`FORCE_FLAG_KW`). Matches upstream baton-do's
    /// `arguments.force`.
    pub force: bool,
}

/// Remove the collection at `target.collection`. Echoes the
/// input target unchanged on success — pure side-effect operation.
///
/// Data-object inputs are an error before any iRODS call.
pub fn rmdir_one(
    conn: &mut RodsConnection,
    target: Target,
    opts: &RmdirOptions,
) -> Result<Target, BatonError> {
    let path = match &target {
        Target::Collection(c) => c.collection.clone(),
        Target::DataObject(d) => {
            return Err(BatonError {
                code: -1,
                message: format!(
                    "baton-do rmdir: target is a data object, not a collection: {}/{}",
                    d.collection, d.data_object
                ),
            });
        }
    };
    conn.rm_collection(&path, opts.recurse, opts.force)?;
    Ok(target)
}

/// Same as [`rmdir_one`], but catches iRODS errors and emits the
/// input annotated with an `"error"` field instead of
/// propagating. Mirrors the rest of the operations layer's
/// `*_one_annotated` wrappers.
pub fn rmdir_one_annotated(
    conn: &mut RodsConnection,
    target: Target,
    opts: &RmdirOptions,
) -> Target {
    let fallback = target.clone();
    match rmdir_one(conn, target, opts) {
        Ok(t) => t,
        Err(err) => {
            let mut annotated = fallback;
            annotated.set_error(err);
            annotated
        }
    }
}
